// Serverless endpoint: POST /api/music-identity
// Accepts a taste profile (averaged audio features) and returns a Music Identity
// generated by Claude Haiku. ANTHROPIC_API_KEY stays server-side only.

const ANTHROPIC_API_URL = 'https://api.anthropic.com/v1/messages'

const SYSTEM_PROMPT = `You are a music personality analyst who turns listening data into vivid, poetic music identities.
Given a user's library (sample songs and optionally their audio feature averages), produce a creative identity.

Rules:
- identity name: 2–3 words, evocative (e.g. "Night Explorer", "Rhythm Alchemist", "Velvet Dreamer")
- description: 2 sentences that feel personal, not technical — describe the emotional journey they go on
- genreDistribution: array of { genre, pct } objects summing to 100, max 5 genres, inferred from artist/song names or audio profile
- moodCharacteristics: 3–5 short mood words/phrases (e.g. "Introspective", "Late-night energy", "Lush textures")
- Respond ONLY with valid JSON — no markdown, no extra text.`

function buildPrompt(profile, songHints) {
  const hints = songHints?.length
    ? `Sample songs from their library:\n${songHints.slice(0, 20).map(s => `- "${s.title}" by ${s.artist}`).join('\n')}`
    : ''

  const featureSection = profile && typeof profile.energy === 'number'
    ? `\nAudio feature averages:\n${[
        `Energy: ${(profile.energy * 100).toFixed(0)}% (${profile.energy > 0.7 ? 'high' : profile.energy > 0.4 ? 'medium' : 'low'})`,
        `Valence/Mood: ${(profile.valence * 100).toFixed(0)}% (${profile.valence > 0.6 ? 'positive/happy' : profile.valence > 0.35 ? 'neutral' : 'melancholic/dark'})`,
        `Danceability: ${(profile.danceability * 100).toFixed(0)}%`,
        `Acousticness: ${(profile.acousticness * 100).toFixed(0)}%`,
        `Instrumentalness: ${(profile.instrumentalness * 100).toFixed(0)}%`,
        `Tempo: ${Math.round(profile.tempo)} BPM`,
      ].join('\n')}`
    : ''

  return `Analyze this listener's music taste:

${hints}${featureSection}

Generate their Music Identity. Return ONLY a JSON object:
{
  "name": "string",
  "description": "string",
  "genreDistribution": [{"genre": "string", "pct": number}],
  "moodCharacteristics": ["string"]
}`
}

function parseIdentity(text) {
  const cleaned = text
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/, '')
    .trim()
  const parsed = JSON.parse(cleaned)
  return {
    name:                String(parsed.name || 'Sonic Wanderer'),
    description:         String(parsed.description || ''),
    genreDistribution:   Array.isArray(parsed.genreDistribution) ? parsed.genreDistribution : [],
    moodCharacteristics: Array.isArray(parsed.moodCharacteristics) ? parsed.moodCharacteristics : [],
  }
}

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' })
  }

  const apiKey = process.env.ANTHROPIC_API_KEY
  if (!apiKey) {
    return res.status(500).json({ error: 'ANTHROPIC_API_KEY not configured' })
  }

  const { profile, songHints } = req.body
  if (!songHints?.length && !profile) {
    return res.status(400).json({ error: 'Either songHints or profile is required' })
  }

  try {
    const response = await fetch(ANTHROPIC_API_URL, {
      method: 'POST',
      headers: {
        'x-api-key':         apiKey,
        'anthropic-version': '2023-06-01',
        'content-type':      'application/json',
      },
      body: JSON.stringify({
        model:      'claude-haiku-4-5-20251001',
        max_tokens: 1024,
        system:     SYSTEM_PROMPT,
        messages:   [{ role: 'user', content: buildPrompt(profile, songHints) }],
      }),
    })

    if (!response.ok) {
      const err = await response.json().catch(() => ({}))
      return res.status(response.status).json({
        error: err?.error?.message || `Anthropic API error: ${response.status}`,
      })
    }

    const data     = await response.json()
    const text     = data?.content?.[0]?.text ?? ''
    const identity = parseIdentity(text)

    return res.status(200).json({ identity })
  } catch (err) {
    return res.status(500).json({ error: err.message || 'Internal server error' })
  }
}
